css:
body {
    font-family: 'Segoe UI', sans-serif;
    background: #f4f7fc;
    color: #333;
}

.jobcard-container {
    padding: 20px;
    background: white;
    border-radius: 10px;
}

.header {
    background: linear-gradient(135deg, #1e3c72, #2a5298);
    color: white;
    padding: 20px;
    border-radius: 8px;
    text-align: center;
}

.header h1 {
    margin: 0;
}

.job-id {
    margin-top: 8px;
    font-size: 16px;
    background: rgba(255,255,255,0.2);
    display: inline-block;
    padding: 6px 12px;
    border-radius: 20px;
}

.section {
    margin-top: 25px;
}

.section h2 {
    color: #2a5298;
    border-bottom: 2px solid #2a5298;
    padding-bottom: 5px;
}

.grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
    margin-top: 10px;
}

.problem {
    margin-top: 10px;
    padding: 10px;
    background: #eef3ff;
    border-left: 4px solid #2a5298;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
}

table thead {
    background: #2a5298;
    color: white;
}

table th, table td {
    padding: 8px;
    text-align: center;
    border: 1px solid #ddd;
}

table tbody tr:nth-child(even) {
    background: #f2f6ff;
}

.financials {
    margin-top: 25px;
    padding: 15px;
    background: #f9fafc;
    border-left: 5px solid #1e3c72;
}

.financials .final {
    font-size: 18px;
    font-weight: bold;
    color: #1e3c72;
    margin-top: 8px;
}
